def solve(*args):
    if not args or len(args) < 2:
        raise ValueError("At least two arguments are required.")

    # Assuming the contract specifies that we need to sum the provided numbers
    total = 0
    for arg in args:
        if not isinstance(arg, (int, float)):
            raise TypeError(f"Invalid argument type: {type(arg)}. Expected int or float.")
        total += arg

    return total
